    "prompt": "You are given the content of an email that contains a Facebook security code. Extract the 6-digit security code as an integer and output it as JSON with the field 'code'. The email content is:\n<tool_result_0/>"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Extract the integer value for the field 'code' from the following JSON and output only the integer:\n<query_llm_0/>"
  }
}
