  "tool": "search_emails",
  "args": {
    "query": "TechServices password reset",
    "sender": null
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Extract the password reset link (a URL) for TechServices from the following email content. Return only the URL.\n<tool_result_1/>"
  }
